mapper.select:
select orders.uuid id, party.user_code, party.role_name, orders.symbol symbol, orders.order_no order_no, orders.offset offset, orders.volume volume, orders.symbol_value symbolValue, orders.create_time createtime, orders.close_time closetime, orders.state state, orders.order_price_type order_price_type, orders.close_price close_price, orders.price price, item.name itemname, orders.is_trigger_order is_trigger_order, orders.trigger_price trigger_price, orders.success_volume successVolume, party.user_name , ur.user_name username_parent from t_exchange_apply_order orders left join tz_user party on orders.party_id = party.user_id left join tz_user ur on ur.user_id = party.user_recom left join t_item item on item.symbol = orders.symbol where 1 =1
and party.role_name=#{rolename}
and item.type=#{symbolType}
and party.user_name=#{userName} or party.user_code=#{userName}
and party.user_code=#{userCode}
and orders.order_no=#{orderNo}
and orders.symbol=#{symbol}
and orders.state=#{state}
and orders.offset=#{offset}
and orders.party_id in
#{item}
order by orders.create_time desc

SELECT  AVG(close_price) as  'avgPrice',symbol,SUM(volume) as 'volume' FROM t_exchange_apply_order
 where  party_id=#{userId}  and state=#{state}  and  create_time  between  #{startTime}  and  #{endTime}

        and symbol in

        #{item}



  group by symbol
